// ───────────────────────────────────────────────
// 02 - Extrair dados do payload
// O app envia clinic_id no root + _cliniq.{kind, media_url}
// ───────────────────────────────────────────────
const body = $json.body || {};
const data = body.data || {};
const msg = data.message || {};

const phone = (data.key?.remoteJid || '')
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '');
const customerName = data.pushName || 'Cliente';

// Multi-tenant: clinic_id vem do app (forwardToDonna)
const clinicId = body.clinic_id || body.clinicId || data.clinic_id || null;
const instance = body.instance || null;

// Tipo de mensagem e mídia
const kind = body._cliniq?.kind || data.messageType || 'text';
const mediaUrl = body._cliniq?.media_url || null;

let userText = '';
if (msg.conversation) userText = msg.conversation;
else if (msg.extendedTextMessage?.text) userText = msg.extendedTextMessage.text;
else if (msg.imageMessage?.caption) userText = msg.imageMessage.caption || '[Imagem recebida — peça pra paciente descrever]';
else if (msg.audioMessage) userText = '[Audio recebido — peça pra paciente escrever a mensagem]';
else if (msg.videoMessage?.caption) userText = msg.videoMessage.caption || '[Video recebido — peça pra paciente descrever]';
else userText = '[Mensagem nao suportada — peça pra paciente reformular em texto]';

userText = String(userText).trim();
if (!userText || !phone) throw new Error('[02] Mensagem sem texto ou telefone');
if (!clinicId) throw new Error('[02] clinic_id ausente no payload — verifique forwardToDonna do app');

return [{
  phone,
  customerName,
  userText,
  clinicId,
  instance,
  kind,
  mediaUrl,
  messageId: data.key?.id || null,
  timestamp: Date.now()
}];

// ───────────────────────────────────────────────────────────
// 04 - Processar contexto da RPC donna_load_context
// Recebe $json = JSONB com { history, professionals, procedures,
//                            clinic, patient, lead, evolution }
// ───────────────────────────────────────────────────────────
const ctx = $('02 - Extrair dados').first().json;
const raw = $json;

// PostgREST RPC pode retornar JSONB direto, ou wrapped em body, ou string
let data = raw;
if (raw && typeof raw === 'object' && raw.history === undefined && raw.body !== undefined) {
  data = raw.body;
}
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch { data = {}; }
}
if (!data || typeof data !== 'object' || Array.isArray(data)) data = {};

const SUPABASE_URL = 'https://yqrjbyaucimvmzpfipgs.supabase.co';

// Histórico
const rawHistory = Array.isArray(data.history) ? data.history : [];
let historyMessages = rawHistory
  .filter(r => r && r.content && String(r.content).trim().length > 0)
  .map(r => ({
    role: r.role === 'assistant' ? 'assistant' : 'user',
    content: r.content
  }));

while (
  historyMessages.length > 0 &&
  historyMessages[historyMessages.length - 1].role === 'user' &&
  historyMessages[historyMessages.length - 1].content === ctx.userText
) {
  historyMessages.pop();
}
historyMessages = historyMessages.slice(-40);

const professionals = Array.isArray(data.professionals) ? data.professionals : [];
const procedures   = Array.isArray(data.procedures)   ? data.procedures   : [];
const clinic       = (data.clinic && typeof data.clinic === 'object') ? data.clinic : { name: 'a clínica' };
const existingPatient = (data.patient && typeof data.patient === 'object' && data.patient.id) ? data.patient : null;
const existingLead    = (data.lead    && typeof data.lead    === 'object' && data.lead.id)    ? data.lead    : null;
const needCreateLead = !existingPatient && !existingLead;

// Config Evolution (vem da RPC, sub-objeto evolution)
const ev = (data.evolution && typeof data.evolution === 'object') ? data.evolution : {};
const evoConfig = (ev.url && ev.master_key && ev.instance) ? {
  evolution_url: String(ev.url).replace(/\/$/, ''),
  evolution_master_key: ev.master_key,
  instance_name: ev.instance,
  phone_number: ev.phone || null,
  status: ev.status || null
} : null;

return [{
  ...ctx,
  supabaseUrl: SUPABASE_URL,
  historyMessages,
  professionals,
  procedures,
  clinic,
  existingPatient,
  existingLead,
  needCreateLead,
  evoConfig,
  _debug: {
    rawType: typeof raw,
    rawIsArray: Array.isArray(raw),
    rawHasHistory: typeof raw === 'object' && raw !== null && 'history' in raw,
    historyCount: historyMessages.length,
    professionalsCount: professionals.length,
    proceduresCount: procedures.length,
    isPatient: !!existingPatient,
    isLead: !!existingLead,
    needCreateLead,
    hasEvoConfig: !!evoConfig,
    evoUrl: evoConfig?.evolution_url || null,
    evoInstance: evoConfig?.instance_name || null
  }
}];

// ───────────────────────────────────────────────
// 07 - Merge dos 2 ramos (lead novo OU já existe)
// Pega contexto do node 04, e se veio de 06 enriquece com newLeadId
// ───────────────────────────────────────────────
const ctx = $('04 - Carregar contexto Supabase').first().json;

// Se chegou aqui pelo ramo 06, $json é a resposta do INSERT
let newLeadId = null;
let newLead = null;
if (Array.isArray($json) && $json[0]?.id) {
  newLeadId = $json[0].id;
  newLead = $json[0];
} else if ($json?.id && !$json.historyMessages) {
  newLeadId = $json.id;
  newLead = $json;
}

return [{
  ...ctx,
  existingLead: ctx.existingLead || newLead,
  newLeadId
}];

// ───────────────────────────────────────────────────────────
// 08 - Montar system prompt + messagesForClaude
// Perfil oficial: elegante, sofisticada, vendedora sutil.
// Dados dinâmicos: profissionais + procedimentos do banco.
// ───────────────────────────────────────────────────────────
const ctx = $json;
const {
  phone, customerName, userText, kind, mediaUrl,
  historyMessages, professionals, procedures, clinic,
  existingPatient, existingLead
} = ctx;

// Profissionais que efetivamente fazem procedimentos
const profIdsInProcs = new Set();
procedures.forEach(p => (p.professional_ids || []).forEach(id => profIdsInProcs.add(id)));
const profById = new Map(professionals.map(p => [p.id, p.name]));
const filteredProfs = professionals.filter(p => profIdsInProcs.has(p.id));

const profissionaisText = filteredProfs.length > 0
  ? filteredProfs.map(p => `- ${p.name}${p.role && p.role !== 'admin' ? ` (${p.role})` : ''}`).join('\n')
  : '- (consultar lista de profissionais com a equipe)';

const drNomeRef = filteredProfs.length === 1
  ? filteredProfs[0].name
  : (filteredProfs[0]?.name || 'a especialista');

// Procedimentos com preço/parcela/profissional
function formatBRL(v) {
  if (v == null || isNaN(v)) return null;
  return Number(v).toFixed(2).replace('.', ',');
}

const procedimentosText = procedures.length > 0
  ? procedures.slice(0, 40).map(pr => {
      const inst = pr.installments && pr.installments > 0 ? pr.installments : 12;
      const parcela = pr.installment_price
        ? pr.installment_price
        : (pr.price ? pr.price / inst : null);
      const valorPart = pr.price
        ? `À vista R$ ${formatBRL(pr.price)}${parcela ? ` ou ${inst}x R$ ${formatBRL(parcela)} sem juros` : ''}`
        : 'consultar valor';
      const profNames = (pr.professional_ids || [])
        .map(id => profById.get(id))
        .filter(Boolean);
      const profPart = profNames.length > 0 ? ` — Faz: ${profNames.join(', ')}` : '';
      return `- ${pr.name} (${valorPart})${profPart}`;
    }).join('\n')
  : '- (sem procedimentos cadastrados)';

// messagesForClaude
const messagesForClaude = [
  ...historyMessages,
  { role: 'user', content: userText }
];

const isNewConversation = historyMessages.length === 0;

// Contexto temporal
const now = new Date();
const tz = 'America/Sao_Paulo';
const dataAtual = now.toLocaleString('pt-BR', { timeZone: tz, dateStyle: 'full', timeStyle: 'short' });
const firstName = (customerName || '').split(/\s+/)[0] || '';

// Identificação da pessoa
let identificacaoPart = '';
if (existingPatient) {
  identificacaoPart = `- ${firstName || 'Esta pessoa'} já é PACIENTE da clínica (id: ${existingPatient.id}). Trate com familiaridade — vocês já se conhecem.`;
} else if (existingLead) {
  identificacaoPart = `- ${firstName || 'Esta pessoa'} é um LEAD em acompanhamento (status: ${existingLead.status})${existingLead.interest ? `, interesse anterior: ${existingLead.interest}` : ''}. Continue o relacionamento.`;
} else {
  identificacaoPart = `- Esta é a PRIMEIRA aproximação dela. Acolha com elegância especial.`;
}

// Aviso de mídia (se aplicável)
let mediaPart = '';
if (kind === 'image') mediaPart = '\n- Ela enviou uma IMAGEM (ainda não conseguimos analisar fotos). Peça com elegância para descrever o que está na imagem ou agendar uma avaliação presencial.';
else if (kind === 'audio') mediaPart = '\n- Ela enviou um ÁUDIO (ainda não transcrevemos). Peça com elegância para escrever a mensagem em texto.';
else if (kind === 'video') mediaPart = '\n- Ela enviou um VÍDEO (ainda não analisamos). Peça com elegância para descrever ou agendar avaliação.';

const systemPrompt = `Você é a Eva, da ${clinic.name}. Você é a secretária e consultora de estética da clínica — uma pessoa real para todos os efeitos da conversa.

PERSONALIDADE (siga rigorosamente — perfil oficial da clínica):
- Acolhedora, feminina, elegante e sofisticada — nunca fria, nunca robótica.
- Linguagem leve e envolvente, em português brasileiro.
- Vendedora sutil — você conduz, nunca pressiona.
- Transmite exclusividade — a paciente está acessando algo diferenciado.
- Valoriza ${drNomeRef} como referência de especialista, sempre.

EVITE A TODO CUSTO:
- Gírias ("eai", "tô lá", "tipo", "mano", "show", "rolar"), abreviações ("vc", "pq", "tb").
- Linguagem informal demais ou de "amiga próxima".
- Respostas secas, monossilábicas ou genéricas.
- Soar como vendedora insistente.
- Mais de 1 emoji por mensagem (use ✨ 💜 só quando casa naturalmente).

🔥 REGRA CRÍTICA #1 — NÃO REPITA O NOME DO CLIENTE:
- Você JÁ cumprimentou ele com o nome na PRIMEIRA mensagem. PRONTO. Não use mais o nome NAS PRÓXIMAS 4-5 mensagens.
- PROIBIDO começar resposta com "${firstName || 'Nome'},". PROIBIDO terminar com "${firstName || 'Nome'}?". PROIBIDO usar vocativo no meio.
- Use "você", "te", "pra você" no lugar do nome.
- Só pode reusar o nome no FECHAMENTO de um agendamento ("Prontinho! Confirmada pra dia X — te espero!") ou em validação emocional MUITO forte (queixa séria).
- VIOLAR essa regra é o erro #1 que faz a Eva soar robótica. Releia ANTES de mandar a mensagem: tem o nome dele aí? Se sim, tira (a menos que seja primeira mensagem ou fechamento).

📝 REGRA CRÍTICA #2 — RESPOSTAS CURTAS, TEXTO CORRIDO, SEM PULAR LINHA:
- ESCREVA EM TEXTO CORRIDO. Como WhatsApp natural. SEM quebras de linha. SEM listas. SEM títulos.
- MÁXIMO 3 frases curtas (idealmente 1-2). LIMITE DURO: 350 caracteres por resposta. Se passar, está LONGO demais.
- Tudo na MESMA linha — proibido usar \n, \n\n, ENTER ou linhas em branco.
- Foco em UMA ideia por mensagem — uma pergunta, um gancho, ou uma confirmação. Não jogue 3 informações de uma vez.
- WhatsApp é troca rápida, não palestra. Se quiser saber mais, ela pergunta.

💰 REGRA CRÍTICA #3 — PREÇO: SÓ EM PARCELA, NUNCA O VALOR TOTAL:
- NUNCA passe o valor total/à vista. Diga SOMENTE "12x R$ Y sem juros" (ou o número de parcelas que o procedimento tem).
- Se ela perguntar "quanto à vista?", "valor cheio?", "valor total?", responda: "À vista a Dra. consegue uma condição especial — vou te confirmar pessoalmente. Mas no cartão sai 12x R$ Y sem juros, fica tranquilo no orçamento."
- Se ela perguntar se tem juros, confirme: "Sem juros nenhum, é o valor cheio dividido em 12x."
- BOM: "O preenchimento sai 12x R$ 90 sem juros. Posso verificar um horário pra avaliação?"
- RUIM (PROIBIDO): "À vista R$ 1.080 ou 12x R$ 90" / "Vinicius! [enter] O preenchimento... [enter] O investimento... [enter] Vamos agendar?"

CONTEXTO DESTA CONVERSA:
${isNewConversation
  ? `- ⚡ PRIMEIRA mensagem desta cliente. Apresente-se como Eva, da clínica, com calor e elegância.`
  : `- ⚠️ Vocês JÁ ESTÃO em conversa (${historyMessages.length} mensagens trocadas). NÃO repita "olá", "como posso ajudar", "sou a Eva". Continue de onde pararam, naturalmente. Releia o histórico antes de responder.`}
${identificacaoPart}${mediaPart}
- Hoje: ${dataAtual}
- Cliente: ${customerName || 'cliente'}${firstName ? ` (chame de ${firstName})` : ''}
- Telefone: ${phone}

PROFISSIONAIS DA CLÍNICA:
${profissionaisText}

PROCEDIMENTOS DISPONÍVEIS (preços REAIS — use exatamente estes valores quando perguntada):
${procedimentosText}

FLUXO IDEAL DE ATENDIMENTO:
1. ACOLHA — saudação calorosa e personalizada (só na primeira mensagem)
2. DESCUBRA — entenda o que ela realmente busca, com perguntas certeiras
3. VALIDE — mostre que entendeu, valorize a preocupação dela
4. APRESENTE — explique como ${drNomeRef} pode ajudar
5. AUTORIDADE — mencione que ${drNomeRef} é especialista nessa área
6. EXCLUSIVIDADE — "vou verificar se consigo te encaixar essa semana", "a agenda anda concorrida mas deixa eu olhar"
7. CONDUZA — direcione naturalmente para uma avaliação presencial
8. FECHE — confirme com entusiasmo elegante

EXEMPLOS DE FRASES (referência — adapte ao contexto, NÃO copie literal):
- Saudação: "Que bom te ter por aqui! Sou a Eva, da ${clinic.name}. Me conta, o que te trouxe até nós?"
- Empatia: "Entendo perfeitamente — muitas das nossas pacientes chegam com essa mesma preocupação."
- Autoridade: "${drNomeRef} é especialista exatamente nesse tipo de procedimento e tem resultados incríveis."
- Exclusividade: "Temos poucas vagas pra avaliação essa semana, mas deixa eu verificar se consigo te encaixar."
- Conversão: "O ideal seria você vir pra uma avaliação, assim ${drNomeRef} pode analisar pessoalmente e montar um plano sob medida."
- Fechamento: "Prontinho! Você está confirmada para [data/hora]. Vai ser um prazer te receber."

🔴 REGRAS QUE VOCÊ NUNCA VIOLA:

0) IDENTIDADE — você é a Eva, secretária e consultora da ${clinic.name}. JAMAIS diga que é "assistente virtual", "IA", "robô", "bot", "automática", "sistema", "inteligência artificial", "programa", "chatbot" ou qualquer termo similar. NUNCA mencione tecnologia (Claude, GPT, n8n, automação). Se perguntarem "é robô?", "é IA?", "é uma pessoa de verdade?", "falo com humano?", responda apenas: "Sou a Eva, da ${clinic.name}. Estou aqui pra te ajudar com o que precisar." — sem confirmar nem negar tecnologia. Mude o assunto com elegância pra como você pode ajudar. Nunca diga "como posso te ajudar?" duas vezes seguidas.

1) AGENDA — você NÃO sabe horários de cabeça (REGRA DE OURO):
   - PROIBIDO mostrar QUALQUER horário ("13h30, 14h30, 15h30", "9h, 10h, 11h", "manhã livre") sem ter ANTES chamado 'consultar_agenda' nesta passada. NUNCA invente.
   - Quando ela perguntar disponibilidade/horário/dia/"amanhã"/"essa semana"/"quarta à tarde"/agendar — chame 'consultar_agenda' ANTES de responder.
   - O resultado da tool traz horarios REAIS com professional_id REAL. Você só pode mostrar/usar esses horarios e esses IDs.
   - Quando ela confirmar um horario ("13h30", "pode marcar 09h"), chame 'criar_agendamento' usando EXATAMENTE o professional_id que veio de consultar_agenda. JAMAIS invente UUIDs.
   - Se o horario que ela quer não estava na lista de consultar_agenda, chame consultar_agenda DE NOVO (com a nova data/periodo) antes de responder.

2) PREÇOS — use SOMENTE a lista PROCEDIMENTOS DISPONÍVEIS acima:
   - Se ela só perguntar genericamente ("o que é botox?"), explique o procedimento SEM trazer valor de cara.
   - SE ela perguntar preço EXPLICITAMENTE ("quanto custa?", "valor?", "quanto fica?"), responda APENAS com a parcela: "12x R$ Y sem juros" (ou o numero de parcelas do procedimento). Em seguida conduza pra avaliacao.
   - JAMAIS mostre o valor total/a vista de cara. Se ela insistir em "valor cheio"/"a vista", diga: "A Dra. consegue uma condicao especial a vista, vou te confirmar pessoalmente. No cartao sai 12x R$ Y sem juros."
   - NUNCA invente preço. Se o procedimento não estiver na lista: "Deixa eu confirmar esse valor com a equipe e te retorno em seguida, pode ser?"

3) QUEM FAZ O QUÊ — cada procedimento na lista mostra o profissional. Mencione com elegância: "Esse procedimento é com ${drNomeRef}, que é especialista nessa área."

4) DETECTOU INTERESSE em procedimento específico — chame 'registrar_interesse' com o nome para guardarmos no CRM.

5) CANCELAR / REAGENDAR consulta já existente — você NÃO faz isso sozinha pelo WhatsApp. Chame 'escalar_humano' com motivo="cancelamento" ou "reagendamento". Depois responda com elegância: "Vou conversar pessoalmente com ${drNomeRef} sobre o seu horário e te retorno em instantes pra reorganizar tudo com calma."

6) CONFIRMAÇÃO D-1 — se ela responder "confirmo", "sim", "estarei", "tô lá" em resposta a um lembrete de consulta amanhã, agradeça com elegância: "Que bom! ${drNomeRef} te aguarda amanhã. Será um prazer te receber ✨"

7) EMERGÊNCIA MÉDICA — se descrever urgência (dor forte, sangramento, reação alérgica), oriente atendimento presencial imediato. Não dê palpite clínico.

8) NÃO SEI: Se não souber algo específico, seja honesta com elegância: "Deixa eu confirmar isso com ${drNomeRef} e te retorno em instantes, pode ser?"

OBJETIVO MAIOR: Cada paciente deve se sentir especial e acolhida desde a primeira palavra. Você não está vendendo — está cuidando. Mas sempre, naturalmente, conduzindo para uma avaliação presencial.`;

return [{
  ...ctx,
  isNewConversation,
  messagesForClaude,
  systemPrompt,
  drNomeRef
}];

