// ───────────────────────────────────────────────
// 10 - Analisar resposta do Claude
// ───────────────────────────────────────────────
const claude = $json;
const ctx = $('08 - Montar contexto Claude').first().json;

const stop = claude.stop_reason;
const content = claude.content || [];

const toolUse = content.find(b => b.type === 'tool_use');

if (stop === 'tool_use' && toolUse) {
  return [{
    ...ctx,
    hasToolUse: true,
    toolName: toolUse.name,
    toolUseId: toolUse.id,
    toolInput: toolUse.input,
    claudeContentBlocks: content
  }];
}

const textBlock = content.find(b => b.type === 'text');
function sanitize(t) {
  if (!t) return t;
  return String(t).replace(/\r/g, '').replace(/\n+/g, ' ').replace(/[ \t]{2,}/g, ' ').trim();
}
return [{
  ...ctx,
  hasToolUse: false,
  finalText: sanitize(textBlock?.text) || 'Desculpe, tive um problema. Pode repetir?'
}];

// ───────────────────────────────────────────────
// CONSULTAR_AGENDA — passo 1: parsear periodo e montar RPC
// ───────────────────────────────────────────────
const ctx = $json;
const { toolInput, supabaseUrl, clinicId, toolUseId, claudeContentBlocks } = ctx;

const periodo = toolInput.periodo || 'hoje';
const tz = 'America/Sao_Paulo';
const now = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));

function pulaFimDeSemana(d) {
  while (d.getDay() === 0 || d.getDay() === 6) {
    d.setDate(d.getDate() + 1);
  }
  return d;
}

function parseData(texto) {
  const t = String(texto || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
  const d = new Date(now);
  if (t.includes('hoje')) return d;
  if (t.includes('depois de amanha')) { d.setDate(d.getDate() + 2); return pulaFimDeSemana(d); }
  if (t.includes('amanha')) { d.setDate(d.getDate() + 1); return pulaFimDeSemana(d); }
  // 'semana que vem', 'proxima semana', 'sem que vem' => próxima segunda-feira
  if (t.includes('semana que vem') || t.includes('proxima semana') || t.includes('sem que vem') || t.includes('outra semana')) {
    const dow = d.getDay();
    const daysToNextMon = ((1 - dow) + 7) % 7 || 7;
    d.setDate(d.getDate() + daysToNextMon);
    return d;
  }
  // 'essa semana', 'esta semana' => próximo dia útil
  if (t.includes('essa semana') || t.includes('esta semana') || t.includes('nessa semana')) {
    d.setDate(d.getDate() + 1);
    return pulaFimDeSemana(d);
  }
  const diasSemana = {'domingo':0,'segunda':1,'terca':2,'quarta':3,'quinta':4,'sexta':5,'sabado':6};
  for (const [dia, num] of Object.entries(diasSemana)) {
    if (t.includes(dia)) {
      const diff = ((num - d.getDay()) + 7) % 7 || 7;
      d.setDate(d.getDate() + diff);
      return d;
    }
  }
  const m1 = t.match(/(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?/);
  if (m1) {
    const dia = parseInt(m1[1]);
    const mes = parseInt(m1[2]) - 1;
    let ano = m1[3] ? parseInt(m1[3]) : d.getFullYear();
    if (ano < 100) ano += 2000;
    const p = new Date(ano, mes, dia);
    if (p < now && !m1[3]) p.setFullYear(ano + 1);
    return p;
  }
  // Fallback: próximo dia útil (não 'amanhã' cego)
  d.setDate(d.getDate() + 1);
  return pulaFimDeSemana(d);
}

function detectarPeriodo(texto) {
  const t = String(texto || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (t.includes('manha')) return 'manha';
  if (t.includes('tarde')) return 'tarde';
  if (t.includes('noite')) return 'noite';
  return null;
}

const dataAlvo = parseData(periodo);
const periodoAlvo = detectarPeriodo(periodo);
const dataStr = `${dataAlvo.getFullYear()}-${String(dataAlvo.getMonth()+1).padStart(2,'0')}-${String(dataAlvo.getDate()).padStart(2,'0')}`;

// Procedimento: tenta resolver pelo nome (fuzzy match nos procedures)
let procedureId = null;
if (toolInput.procedimento && Array.isArray(ctx.procedures)) {
