// ───────────────────────────────────────────────
// CRIAR_AGENDAMENTO — passo 1: montar payloads
// + VALIDAR professional_id (Claude as vezes alucina UUID)
// + Fallback inteligente: nome do profissional no historico
// ───────────────────────────────────────────────
const ctx = $json;
const {
  toolInput, clinicId, phone, existingPatient,
  professionals = [], procedures = [], historyMessages = []
} = ctx;

const [hh, mm] = String(toolInput.horario).split(':').map(Number);
const startIso = `${toolInput.data}T${String(hh).padStart(2,'0')}:${String(mm).padStart(2,'0')}:00-03:00`;
const endMinutes = hh*60 + mm + 30;
const endH = Math.floor(endMinutes/60);
const endM = endMinutes % 60;
const endIso = `${toolInput.data}T${String(endH).padStart(2,'0')}:${String(endM).padStart(2,'0')}:00-03:00`;

function norm(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

// Resolver procedure_id pelo nome
let procedureId = null;
if (toolInput.procedimento && Array.isArray(procedures)) {
  const needle = norm(toolInput.procedimento);
  const found = procedures.find(p => {
    const hay = norm(p.name);
    return hay.includes(needle) || needle.includes(hay);
  });
  if (found) procedureId = found.id;
}

// 🔥 VALIDAR professional_id
const validProfIds = new Set(professionals.map(p => p.id));
let professionalId = toolInput.professional_id;
let profSource = 'claude';

if (!validProfIds.has(professionalId)) {
  let matched = null;
  // Fallback 1: nome do profissional mencionado nas ultimas msgs do assistant
  const lastAssistantTexts = historyMessages.filter(m => m.role === 'assistant').slice(-3).map(m => norm(m.content));
  for (const p of professionals) {
    const pNorm = norm(p.name).replace(/^dra?\.?\s+/, '');
    const firstName = pNorm.split(/\s+/)[0];
    if (!firstName) continue;
    if (lastAssistantTexts.some(t => t.includes(firstName))) { matched = p; profSource = 'historico-assistant'; break; }
  }
  // Fallback 2: nome mencionado pelo usuario
  if (!matched) {
    const lastUserTexts = historyMessages.filter(m => m.role === 'user').slice(-3).map(m => norm(m.content));
    for (const p of professionals) {
      const pNorm = norm(p.name).replace(/^dra?\.?\s+/, '');
      const firstName = pNorm.split(/\s+/)[0];
      if (!firstName) continue;
      if (lastUserTexts.some(t => t.includes(firstName))) { matched = p; profSource = 'historico-user'; break; }
    }
  }
  // Fallback 3: primeiro profissional do procedimento
  if (!matched && procedureId) {
    const proc = procedures.find(p => p.id === procedureId);
    if (proc?.professional_ids?.length) {
      matched = professionals.find(p => p.id === proc.professional_ids[0]);
      if (matched) profSource = 'procedimento';
    }
  }
  // Fallback 4: se so tem 1 profissional, usa ele
  if (!matched && professionals.length === 1) {
    matched = professionals[0];
    profSource = 'unico-profissional';
  }
  if (matched) professionalId = matched.id;
}

const profValid = validProfIds.has(professionalId);

// Se NAO conseguimos validar/corrigir → bypass criacao e gera toolResult de erro
if (!profValid) {
  return [{
    ...ctx,
    skipCreate: true,
    patientAlreadyExists: true, // bypass o IF 14b
    patientId: existingPatient?.id || '00000000-0000-0000-0000-000000000000',
