    _debug13b: { profSource: 'NAO_RESOLVIDO', original: toolInput.professional_id, validIds: [...validProfIds] }
  }];
}

const patientAlreadyExists = !!existingPatient;
const patientId = existingPatient?.id || null;

return [{
  ...ctx,
  skipCreate: false,
  startIso,
  endIso,
  procedureId,
